// 🔥 Get all email subjects from Gmail node
const allMails = $items("📥 Fetch Sophos Reports (Gmail)");

// ✅ Backup keyword (tera actual subject pattern)
const backupKeyword = "daily auto backup";

// ✅ Check if ANY mail matches
let backupFound = false;

for (const mail of allMails) {
  const subject = (mail.json.subject || "").toLowerCase();

  if (subject.includes(backupKeyword)) {
    backupFound = true;
    break;
  }
}

// ✅ Final status
return [
  {
    json: {
      backup_status: backupFound ? "YES" : "NO"
    }
  }
];

