let res = $json.choices[0].message.content;

res = res.replace(/```json/g, "").replace(/```/g, "").trim();

let data;

try {
  data = JSON.parse(res);
} catch (e) {
  data = {};
}

data = data || {};

// =====================================================
// ✅ CLEAN FUNCTION
// =====================================================

const clean = (arr, key) => {
  if (!Array.isArray(arr)) return [];
  return arr.filter(x => x && x[key]).slice(0, 5);
};

data.high_usage_users = clean(data.high_usage_users, "bytes");
data.top_websites = clean(data.top_websites, "bytes");
data.top_applications = clean(data.top_applications, "bytes");
data.top_user_groups = clean(data.top_user_groups, "bytes");
data.top_categories = clean(data.top_categories, "bytes");

// =====================================================
// 🔥 HIGH RISK APPLICATIONS (LLM BASED - FINAL FIX)
// =====================================================

// 👉 agar LLM ne already diya hai to use karo
if (Array.isArray(data.high_risk_apps) && data.high_risk_apps.length > 0) {

  // safety clean
  data.high_risk_apps = data.high_risk_apps
    .filter(x => x && x.app && x.bytes)
    .slice(0, 5);

} else {
  data.high_risk_apps = [];
}

// =====================================================
// ✅ APPLICATION RISK (already from LLM)
// =====================================================

const riskVal = parseFloat(data.application_risk);

if (!isNaN(riskVal)) {
  if (riskVal >= 0.7) data.risk_level = "High";
  else if (riskVal >= 0.4) data.risk_level = "Medium";
  else data.risk_level = "Low";
} else {
  data.risk_level = "Low";
}

// =====================================================
// ✅ SUMMARY
// =====================================================

data.summary = `
This is an automated consolidated security report generated from multiple Sophos logs.

• Overall Risk Level: ${data.risk_level}
• Application Risk Score: ${data.application_risk || "N/A"}

Key Observations:
- Top internet usage observed among selected users
- Critical applications contributing highest traffic identified
- ${
  data.high_risk_apps && data.high_risk_apps.length > 0
    ? "High-risk applications detected and require attention"
    : "No high-risk applications detected"
}

This report provides a quick overview for monitoring security posture and user activity.
`.trim();

// =====================================================

return [{ json: data }];
